<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list ref="tgList" :listType="listType" :IsShowAction="true" :showCheckBox="true"
            ModuleName="PROJECT" SubModuleCode="Project_Detail" IdentityColumn="project_id"
            :HeaderText="$t('Manage Project')" :ListData="ProjectData" :HeaderData="Headers" :widgets="widgets"
            :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields"
            :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData" :SortExp="SortExp"
            :ViewList="ViewList" v-on:ApplyView="OnApplyView" :SortBy="SortBy" :LegendArray="LegendArray"
            :NorecordfoundText="$t('NoRecordfound')" v-on:LeftsearchButtonClick="leftCommonSearch" :isNewDesign="isNewDesign"
            v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick"
            v-on:ActionButtonClick="actionButtonClick" v-on:SortdataButtonClick="sortdata" :key="Key" :routeInfo="$router">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'status_id' && (UserType != 'NU' && UserType != 'CL')">
                    <listing-status :isfor="'PROJECTLISTING'" ref="updatestatus" v-bind:dataid="data.row.project_id"
                        data-controller="PROJECT" v-bind:statuslist="StatusListForListing" v-bind:item="data"
                        data-action="index" v-bind:dataselected="data.row.project_status"  :disabled="data.row.project_status === 'Active'"
                        v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true">
                    </listing-status>
                    
                </template>
                <template v-if="data.column.COLUMN_NAME == 'status_id' && (UserType == 'NU' || UserType == 'CL')">
                    <a class="inactive-disabled">
                        <span v-bind:style="{ backgroundColor: data.row.status_bg_color }"
                            class="text-center text-white d-block">
                            {{ data.row.project_status }}
                        </span>
                    </a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'planned_start_date'">
                  <span :title="data.row.planned_start_date != null ? $d(data.row.planned_start_date) : '--'">
                    {{ data.row.planned_start_date != null ? $d(data.row.planned_start_date) : '--' }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'planned_end_date'">
                 <span :title="data.row.planned_end_date != null ? $d(data.row.planned_end_date) : '--'">
                    {{ data.row.planned_end_date != null ? $d(data.row.planned_end_date) : '--' }}
                 </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'priority_id'">                                 
                        <span v-bind:style="{ backgroundColor: data.row.color_code }" v-if="data.row.priority_id !=''"
                            class="text-center text-white d-block">
                            {{  data.row.priority_id  }}   
                        </span>
                        <span v-else v-bind:style="{ backgroundColor: data.row.color_code }" 
                            class="text-center d-block">
                            {{  'N/A'  }}   
                        </span>
                </template>

                <template v-if="data.column.COLUMN_NAME == 'current_progress'">
                  <span class="d-flex">
                    <div class="Task clockposition">
                        <div>
                            <progress id="progress-bar-1" :value="data.row.current_progress" max="100"></progress>
                            <div class="vue-simple-progress-text" id="progress-text"
                                style="color: rgb(34, 34, 34); font-size: 12px; text-align: center; padding-top: 3px;">
                                {{ data.row.current_progress }} % {{ $t('Completed') }}</div>
                        </div>
                    </div>
                    <a v-if="(data.row.IS_INCLUDE_IN_TASK > 0 || UserType != 'CL') && data.row.PROJECTTASKPROGRESS != 'TIMER_BASED'"
                        class="text-success align-top mt-0 d-inline-block text-right" data-toggle-tooltip="tooltip"
                        data-original-title="Manage Progress" @click="EditTaskProgress(data.row, this)">
                        <i class="fa fa-clock-o text-secondary float-left"></i>
                    </a>
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'project_name'">
                    <em class="fa fa-thumb-tack font-13 text-dark pr-2 float-left pt-1"
                        v-on:click="MarkAsUnPin(data.row.project_id)" v-if="data.row.pin_id > 0"></em>
                    <span :title="data.row.project_name" style="color: dodgerblue;cursor: pointer; white-space: nowrap;  word-wrap: break-word;  overflow: hidden;  display: block;  text-overflow: ellipsis;
                         "  @click="ProjectDetail(data.row)"> {{ data.row.project_name }}</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'estimated_hours'">
                    {{ $n(data.row.estimated_hours,'decimal2')}}                    
                </template>
                <template v-if="data.column.COLUMN_NAME == 'currency_conversion_rate'">
                    <span>{{ $n(data.row.currency_conversion_rate,'decimal2') + ' ' + data.row.iso_code}}/</span>
                    <span class="bg-warning text-dark">{{$n(data.row.orignal_convertion_amount,'decimal2') == 'NaN' ?'0.00' : $n(data.row.orignal_convertion_amount,'decimal2') }}</span>
                </template>              
                <template v-if="data.column.COLUMN_NAME == 'estimated_cost'">
                  <span :title=" $n(data.row.estimated_cost,'currency', $getLocaleByCurrency(data.row.iso_code))">
                    {{ $n(data.row.estimated_cost,"currency", $getLocaleByCurrency(data.row.iso_code)) }}
                  </span>
                </template>

                <template v-if="data.column.COLUMN_NAME == 'template_id'">
                  <span :title="data.row.TEMPLATE_NAME">
                   {{ data.row.TEMPLATE_NAME }}
                  </span>
                </template>
                 <template v-if="data.column.COLUMN_NAME == 'industry_type_id'">
                  <span :title="data.row.INDUSTRY_NAME">
                    {{ data.row.INDUSTRY_NAME }}
                  </span>
                </template>
            </template>
            <template v-slot:customcard="{ data }">
                <div class="card-box pb-0"
                    v-bind:class="{ 'green-bg-light': data.row.is_virtual_user_enabled == true, 'blue-bg-light': data.row.is_virtual_user_enabled == false, 'samplebar_card': data.row.is_sample_data == 1 }"
                    v-bind:style="{ 'border': '2px solid' + data.row.is_virtual_user_enabled, 'border-top': '5px solid' + data.row.is_virtual_user_enabled }">
                    <div class="card-number">
                        <div class="custom-control custom-checkbox custom-control-inline">
                            <input type="checkbox" class="chkItems custom-control-input"
                                v-on:change="ForCheckBoxClear($event)" :value="data.row.project_id"
                                :id="'chk' + data.row.project_id" style="display: none;">
                            <label class="custom-control-label" type="checkbox"
                                :for="'chk' + data.row.project_id"></label>
                            <a title="" class="text-truncate expense-title ml-1 pt-1" :value="data.row.project_id"
                                data-toggle-tooltip="tooltip" style="cursor: default;" data-original-title="text">{{
                                    TruncateStr(data.row.project_name,34) }}</a>
                        </div>
                    </div>
                    <div class="card-detail-main">
                        <div class="card-detail">
                            <em class="fa fa-exclamation-triangle"></em>
                            <span class="float-left w-auto mr-1">{{ $t('Status') }} -</span>
                            <span class="text-center single-action float-left w-auto"
                                v-if="(data.row.project_status != '' && UserType != 'NU' && UserType != 'CL')">
                                <listing-status
                                    v-if="(UserType != 'NU' && UserType != 'PM' && UserType != 'CL') || data.row.user_type_id != 3"
                                    :isfor="'PROJECTLISTING'" ref="updatestatus" v-bind:dataid="data.row.project_id"
                                    data-controller="PROJECT" v-bind:statuslist="StatusListForListing"
                                    v-bind:item="data" data-action="index" v-bind:dataselected="data.row.project_status"
                                    v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true">
                                </listing-status>
                            </span>
                            <span class="text-center single-action float-left w-auto"
                                v-if="((UserType == 'NU' || UserType == 'PM') && data.row.user_type_id == 3)">
                                <a class="inactive-disabled">
                                    <span class="btn text-center w-100"
                                        v-bind:style="{ 'background-color': data.row.status_bg_color, 'color': data.row.status_color }"
                                        style="cursor: default;">{{ data.row.project_status }}</span>
                                </a>
                            </span>
                        </div>
                        <div class="card-detail"><em class="fa fa-map-marker"></em> <span
                                class="float-left w-auto mr-1">{{
                                    $t('Location') }} - {{ data.row.location_name }}</span></div>                       
                        <div class="card-detail" v-if="UserType != 'CL'"><i class="fa fa-money"></i> <span
                                class="float-left w-auto mr-1">{{ $t('ProjectCost') }} -
                                {{ $n(data.row.estimated_cost,'decimal2') + ' ' + data.row.iso_code }}/
                            </span><span class="bg-warning text-dark px-1 float-left w-auto">{{
                                $n(data.row.orignal_convertion_amount,'decimal2')
                                    == 'NaN' ? '0.00' : $n(data.row.orignal_convertion_amount,'decimal2')
                                }}</span>
                        </div>
                        <div class="card-detail"
                            v-if="(data.row.planned_start_date != null && data.row.planned_end_date != null)">
                            <em class="fa fa-calendar-o" aria-hidden="true"></em>
                            <span class="float-left w-auto mr-1">
                                {{ data.row.planned_start_date != null ? $d(data.row.planned_start_date) : '--' }} - 
                                {{ data.row.planned_end_date != null ? $d(data.row.planned_end_date) : '--' }}
                            </span>
                        </div>
                        <a :id="'a' + data.row.project_id" @click="ShowMore('showdiv' + data.row.project_id)"
                            href="javascript:;" :class="{ 'read-more-content': true, 'hide': ShowMoreFalse == true }">{{
                                $t('More') }}</a>
                        <div :class="{ 'read-more-content': true, 'hide': ShowMoreFalse == false }"
                            :id="'showdiv' + data.row.project_id">
                            <div class="spac-eq border-top text-center">
                                <div class="card-action mt-2 mb-0 w-100 text-center">
                                    <a title="Edit Project"
                                        v-if="UserType != 'NU' && UserType != 'CL' && (data.row.user_type_id == 2 || UserType == 'CA')"
                                        data-placement="left" class="update round-icon-small btn-primary float-none"
                                        checkPrivilege="yes" v-on:click="EditProject(data.row.project_id)"
                                        href="javascript:;" style="cursor:pointer;" v-bind:value="data.row.project_id">
                                        <i class="fa fa-pencil action-icon"></i>
                                        <span class="text">{{ $t('Edit') }}</span>
                                    </a>
                                    <a title="Quick View" data-placement="left"
                                        v-on:click="QuickView(data.row.project_id)"
                                        class="update round-icon-small  btn-success float-none" href="javascript:;"
                                        v-bind:value="data.row.project_id">
                                        <i class="fa fa-eye action-icon"></i>
                                        <span class="text">{{ $t('QuickView') }}</span>
                                    </a>
                                    <a title="Clone Project"
                                        v-if="UserType != 'NU' && UserType != 'CL' && (data.row.user_type_id == 2 || UserType == 'CA')"
                                        v-on:click="OpenCloneProjectModel(data.row.project_id)" id="acreateprojectclone"
                                        class="round-icon-small btn-warning float-none" data-placement="left"
                                        checkPrivilege="yes" v-bind:pid="data.row.project_id" href="javascript:;">
                                        <i class="fa fa-clone text-white action-icon"></i>
                                        <span class="text">{{ $t('CloneProject') }}</span>
                                    </a>
                                    <a title="Edit Project Configurations"
                                        v-if="UserType != 'NU' && UserType != 'CL' && (data.row.user_type_id == 2 || UserType == 'CA')"
                                        data-placement="left" class="aConfig round-icon-small btn-secondary float-none"
                                        v-on:click="openConfigurationModel(data.row.project_id)" checkPrivilege="yes"
                                        href='javascript:;'>
                                        <i class="fa fa-cog action-icon"></i>
                                        <span class="text">{{ $t('Configurations') }}</span>
                                    </a>
                                </div>
                            </div>
                            <div class="spac-eq border-top text-center pt-2">
                                <div class="Task">
                                    <div v-bind:class="'c100 small green p' + parseInt(data.row.current_progress, 10)">
                                        <span>{{ data.row.current_progress }}%</span>
                                        <div class="slice">
                                            <div v-bind:class="{ 'bar': data.row.current_progress > 0 }"></div>
                                            <div class="fill"></div>
                                        </div>
                                    </div>
                                    <span class="t-title">{{ $t('Completed') }}</span>
                                </div>
                            </div>
                            <a id="cardMoreDataLess" @click="ShowLess('showdiv' + data.row.project_id)"
                                href="javascript:;" :class="{ 'read-more-hide': true, '': ShowMoreFalse == true }">{{
                                $t('Less') }}</a>
                        </div>

                         <div title="Unpin" class="verticlepin" @click="MarkAsUnPin(data.row.project_id)" v-if="data.row.pin_id > 0"><em aria-hidden="true"  title="Unpin" class="fa fa-thumb-tack action_icon cursor-pointer"></em></div>
                         <div class="verticle-action">   
                            <em class="fa fa-ellipsis-v action_icon mr-2" @click.stop="openActionIcon($event, data.row.project_id)" aria-hidden="true"></em>
                                <span class="action-list-box d-block" :id="'action-list-box-' + data.row.project_id" style="width: 240px;display:none;">
                                <span class="list-actions fsm-list" id="action-list" style="padding-left:0">
                                    <div v-if="UserType != 'NU' && UserType != 'CL'" class="float-left">
                                        <div v-if="data.row.user_type_id == 2 || UserType == 'CA'" class="float-left">
                                            <a title="AddTeam" data-placement="left" id="btnTeamAdd"
                                                class="update actions-onclick ProjectViewAddbtns" href="javascript:;"
                                                v-bind:value="data.row.project_id" @click="btnTeamAdd(data.row)">
                                                <i class="fa fa-users text-info action-icon mr-1"></i>
                                                <span class="text">{{ $t('AddTeam') }}</span>
                                            </a>
                                            <a title="GanttChart" class="update actions-onclick" data-placement="left" @click="navigateToGanttChart(data.row.project_id,data.row)">
                                                <i class="fa fa-area-chart text-dark action-icon mr-1"></i>
                                                <span class="text">{{ $t('GanttChart') }}</span>
                                            </a>
                                            <a title="RoadMap" class="actions-onclick" target="_blank"
                                                data-placement="left" @click="RoadMap(data.row.project_id)">
                                                <i class="fa fa-line-chart text-primary action-icon mr-1"></i>
                                                <span class="text">{{ $t('RoadMap') }}</span>
                                            </a>
                                            <a v-if="data.row.project_status == 'Active'" class="actions-onclick" @click="Quotation(data.row)"
                                                title="AddQuotation" data-placement="left">
                                                <i class="fa fa-file action-icon mr-1"></i>
                                                <span class="text">{{ $t('Quotation') }}</span>
                                            </a>
                                            <a v-else href="javascript:void(0);" class="actions-onclick" @click="Quotation(data.row)">
                                                <i class="fa fa-file action-icon mr-1"></i>
                                                <span class="text">{{ $t('Quotation') }}</span>
                                            </a>
                                        </div>
                                    </div>
                                    <a v-if="UserType != 'CL'" class="actions-onclick" title="AssignedTasks" @click="AssignedTasks(data.row.project_id)"
                                        data-placement="left" target="_blank" style="display:block;">
                                        <i class="fa fa-clock-o action-icon mr-1"></i>
                                        <span class="text">{{ $t('AssignedTasks') }}</span>
                                    </a>
                                    <i class="fa fa-times close close-action" @click.stop="closeActionIcon($event, data.row.project_id)" aria-hidden="true"></i>
                                </span>
                            </span>
                        </div>
                    </div>
                </div>
            </template>
        </tg-list>
        <UpdateStatusProject v-if="IsUpdateStatusProject" :ProjectIds="IsUpdateStatusProjectId"></UpdateStatusProject>
        <AssignTag v-if="ShowAssignTag" :ProjectIds="IsUpdateStatusProjectId"></AssignTag>
        <ImportProjects v-if="IsImportProjects"></ImportProjects>
        <viewlayout v-if="ShowManageView" v-show="ShowManageView" submodulecode="PROJECT_DETAIL" modulename="PROJECT"
            v-on:close="ShowManageView = false" v-bind:callbackfunction="FetchData" :usertype="UserType">
            <h5 slot="header">{{ $t('Search') }}</h5>
        </viewlayout>
        <AddProject v-show="IsAddProject" :ProjectId="ProjectId" :Type="IsType" @callbackfunction="CloseProjectModal"></AddProject>
        <AddProjectNew v-if="IsAddProjectt" :ProjectId="ProjectId" :Type="IsType" @callbackfunction="CloseProjectModall" :key="key"></AddProjectNew>
        <AddTeam v-if="IsAddTeamShow" :ProjectId="ProjectId" :Type="IsType" @close="HideIsAddTeamShow" @callbackfunction="FetchData" ></AddTeam>
        <MakeProjectDefault v-if="IsMakeProjectDefault" :ProjectId="ProjectId" :ProjectName = "ProjectName"></MakeProjectDefault>
        <ProjectQuickView v-if="IsProjectQuickView" :ProjectId="ProjectId" @ProjectQuickView="ProjectQuickView"></ProjectQuickView>
        <CloneProject v-if="IsCloneProject" :ProjectId="ProjectId"></CloneProject>
        <Configurations v-if="IsConfiguration" :ProjectId="ProjectId"></Configurations>

    </section>
</template>
<script>
import Schema from './ProjectSchema';
import DataService from '../../../services/DataService';
import UpdateStatusProject from '../../../components/Modal/UpdateStatusProject.vue'
import AssignTag from '../../../components/Modal/Manageassigntag.vue'
import ImportProjects from '../../../components/Modal/ImportProjects.vue'
import viewlayout from "../../../components/Common/view-layout.vue";
import AddProject from '../../../components/Modal/AddProject.vue'
import AddTeam from '../../../components/Modal/AddTeam.vue'
import MakeProjectDefault from '../../../components/Modal/MakeProjectDefault.vue'
import ProjectQuickView from '../../../components/Modal/ProjectQuickView.vue'
import CloneProject from '../../../components/Modal/CloneProject.vue'
import Configurations from '../../../components/Modal/ConfigurationModal.vue'
import AddProjectNew from '../../../components/Modal/AddProjectNew.vue'

export default {
    components: {  UpdateStatusProject, AssignTag, ImportProjects, viewlayout, AddProject, AddTeam, MakeProjectDefault, ProjectQuickView, CloneProject, Configurations,AddProjectNew },
    data() {
        return {
            Key:0,            
            IsType:'Project',
            isNewDesign:false,
            isLoading: false,
            IsCloneProject: false,
            ShowMoreFalse: false,
            ProjectId: 0,
            searchCondition: '',
            TotalRecords: 0,
            PageNumber: 1,
            PageSize: 10,
            SortBy: '',
            SortExp: '',
            Headers: [],
            ProjectData: [],
            ViewListId: '',
            viewId: 0,
            ViewList: [],
            listType:['List', 'Card'],
            Type:'',
            listheaderbuttons: Schema.buttons,
            leftSearchFields: Schema.leftsearchSchema,
            listActions: Schema.listActions,
            widgets: [
                {
                    icon: "fa fa-folder",
                    value: "",
                    name: this.$t('Projects'),
                    class: "one_wid",
                    onClick: this.widgetClick
                },
                {
                    icon: "fa fa-folder-open",
                    value: "",
                    name: this.$t('In_Progress'),
                    class: "two_wid",
                    onClick: this.widgetClick
                },
                {
                    icon: "fa fa-dollar",
                    value: "",
                    name: this.$t('TotalRevenue'),
                    class: "three_wid",
                    onClick: this.widgetClick
                },
                {
                    icon: "fa fa-calendar-check-o",
                    value: "",
                    name: this.$t('Completed'),
                    class: "four_wid",
                    onClick: this.widgetClick
                },
                {
                    icon: "fa fa-list-ul",
                    value: "",
                    name: this.$t('Closed'),
                    class: "five_wid",
                    onClick: this.widgetClick
                }
            ],
            LegendArray: [
                {
                    class: 'legend-Progress colorboxsquare',
                    text: (this.$t('VirtualUserEnabled_project', ['Project']))
                },
                {
                    class: 'legend-pending colorboxsquare',
                    text: (this.$t('OriginalCost'))
                }
            ],
            completedStatusId: null,
            ongoingStatusId: null,
            inprogressStatusId: null,
            closedStatusId: null,
            fav: '',
            StatusListForListing: [],
            userId: null,
            companyId: null,
            IsUpdateStatusProject: false,
            IsUpdateStatusProjectId: null,
            ShowAssignTag: false,
            IsImportProjects: false,
            ShowManageView: false,
            UserType: null,
            IsAddProject: false,
            IsAddProjectt:false,
            ProjectEditId: 0,
            IsAddTeamShow: false,
            ProjectId: 0,
            IsMakeProjectDefault: false,
            IsProjectQuickView: false,
            IsConfiguration: false,
            ProjectName: null,
            CurrencyCode:'PKR',
            key:0,
            projectCurrency:''
        }
    },
    created: async function () {  
        var ths = this;
        ths.userId = ths.GetUserInfo.ID;
        ths.companyId = ths.GetUserInfo.CompanyId;
        ths.UserType = ths.GetUserInfo.UserType;
        ths.CurrencyCode = ths.GetUserInfo.Currency.replace(/[()]/g, '');
        if(ths.UserType == 'NU' || ths.UserType == 'CL'){
           var array = ths.listheaderbuttons.filter(obj => obj.title?.toLowerCase() === "pin"); 
           ths.listheaderbuttons = [...array];
        }
        else{
            ths.listheaderbuttons=ths.listheaderbuttons;
        }  
        await ths.GetStatusList();       
        await ths.GetDdlRecords_ViewList();
        await ths.Widget();        
        await Schema.bindleftCommonSearchdropdown(ths, "PROJECT", "CHANNEL");
        await Schema.bindleftCommonSearchdropdown(ths, "PROJECT", "Status");        
        await ths.FetchData(); 
    },

    methods: {        
        ManageView: function () {
            var vm = this;
            vm.ShowManageView = true;
            setTimeout(function () {
                $("#modalManageView").modal("show");
            }, 1000);
        },
        GetDdlRecords_ViewList: async function () {
            var vm = this;
            vm.ViewList = [];
            var url = `moduleName=PROJECT&subModuleCode=PROJECT_DETAIL&viewId=0&pageSize=100&pageNum=1&sortBy=&sortExp=`;
            await DataService.GetViewList(url).then(function (response) {
                if (response.data && typeof (response.data.DATA) != 'undefined') {
                    vm.ViewList = response.data.DATA;
                }
                var chkVACTIVE = 0;
                vm.ViewListId = "0";
                if (vm.ViewList == null || vm.ViewList == "") {

                }
                else {
                    vm.ViewList.forEach(function (item) {

                        if (item.IS_SLECTED_USER_ID > 0) {
                            chkVACTIVE = chkVACTIVE + 1;
                            vm.ViewListId = item.VIEW_ID;
                        }
                    });
                }
                var indx = 0;
                if (chkVACTIVE > 0) {
                    vm.ViewList.splice(indx, 0, { "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 0, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });
                }
                else {
                    if (vm.ViewList == null || vm.ViewList == "") {

                        vm.ViewList.push({ "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 1, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });
                    }
                    else {
                        vm.ViewList.splice(indx, 0, { "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 1, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });

                    }
                }
                setTimeout(() => {
                    if (vm.ViewListId > 0) {
                        vm.$refs.tgList.$refs.tgListHeaderButtons.ViewListId = vm.ViewListId;
                    } else {                        
                        vm.$refs.tgList.$refs.tgListHeaderButtons.ViewListId = "0";
                    }
                }, 1000);

            });
        },
        DefaultView: function () {
            var vm = this;
            var obj = {
