            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'QuickView':
                        action.isVisible = true;
                        break;
                    case 'Edit':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ?true:false;
                        break;
                    case 'Add Team':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ?true:false;
                        break;
                    case 'Gantt Chart':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ?true:false;
                        break;
                    case 'Quotation':
                        action.isVisible = (row.project_status == 'Active' || row.project_status == 'Inprogress' || row.project_status == 'pending') && (row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1)?true:false;
                        break;
                    case 'Road Map':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ?true:false;
                        break;
                    case 'Clone Project':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ?true:false;
                        break;
                    case 'Make it default':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ?true:false;
                        break;
                    case 'Configurations':
                        action.isVisible = row.user_type_id == 2 || self.UserType == 'CA' || row.user_type_id == 1 ?true:false;
                        break;
                    case 'Assigned Tasks':
                        action.isVisible = self.UserType != 'CL'? true:false;
                        break;
