    },
    methods: {
        getTabDisplayName(ShowSelectedIndustry,tabFeature){
            
            let tabname = ''; 
            if (ShowSelectedIndustry === 'Construction') {
                if (tabFeature === 'Project Phase') {
                    tabname = 'Phase';
                } else if (tabFeature === 'Project Stage') {
                    tabname = 'Stage';
                } else if (tabFeature === 'Milestones') {
                    tabname = 'Milestone';                
                } else if (tabFeature === 'Team') {
                    tabname = 'WorkCrew';                   
                } else if (tabFeature === 'Files') {
                    tabname = 'Documents';
                }
            }
            // Marketing industry type mappings
            else if (ShowSelectedIndustry === 'Marketing') {                
                if (tabFeature === 'BackLog') {
                    tabname = 'campaignplan';
                } else if (tabFeature === 'Sprint') {
                    tabname = 'CampaignCycle';
                } else if (tabFeature === 'Project Phase') {
                    tabname = 'CampaignPhase';
                } else if (tabFeature === 'Project Stage') {
                    tabname = 'CampaignStep';
                } else if (tabFeature === 'Tasks') {
                    tabname = 'campaigntask';
                } else if (tabFeature === 'Milestones') {
                    tabname = 'campaignmilestone';
                } else if (tabFeature === 'Team') {
                    tabname = 'marketingteam';
                }
            }
            else if (ShowSelectedIndustry === 'Design') {                
                if (tabFeature === 'BackLog') {
                    tabname = 'DesignBacklog';
                }else if (tabFeature === 'Sprint') {
                    tabname = 'UXSprint';
                } 
                else if (tabFeature === 'Project Phase') {
                    tabname = 'UIDesignPhase';
                } else if (tabFeature === 'Project Stage') {
                    tabname = 'UXStage';
                } else if (tabFeature === 'Tasks') {
                    tabname = 'DesignTask';
                } else if (tabFeature === 'Milestones') {
                    tabname = 'DesignMilestone';
                } else if (tabFeature === 'Team') {
                    tabname = 'UIDesignTeam';
                }
            }

            else if (ShowSelectedIndustry === 'Sales') {
                if (tabFeature === 'BackLog') {
                    tabname = 'DealBacklog';
                }else if (tabFeature === 'Sprint') {
                    tabname = 'SalesCycle';
                } 
                else if (tabFeature === 'Project Phase') {
                    tabname = 'PipelinePhase';
                } else if (tabFeature === 'Project Stage') {
                    tabname = 'DealStage';
                } else if (tabFeature === 'Tasks') {
                    tabname = 'SalesTask';
                } else if (tabFeature === 'Milestones') {
                    tabname = 'DealMilestone';
                } else if (tabFeature === 'Team') {
                    tabname = 'SalesTeam';
                }
            } 
            return tabname !== '' ? tabname : tabFeature;
        },
        GetTemplatesByTemplateId() {
            this.isLoading = true;
            this.Tablistingdata = [];
            var url = `TemplateId=${this.selectedTemplateId}&IndustryId=${this.IndustryId}`
            DataService.GetTemplatesByTemplateId(url).then((response) => {
                this.isLoading = false;
                if (response.data != '') {
                    var Data = JSON.parse(response.data.result);
                    this.Tablistingdata = Data.DATA;
                    this.Tablistingdata.forEach((element) => {
                        if (element.is_required) {

                            this.$set(element, 'isActive', true);
                            this.$set(element, 'isMandatory', true);
                            this.$set(element, 'isSelected', true);
                        }
                        else {
                            this.$set(element, 'isActive', false);
                            this.$set(element, 'isSelected', false);
                        }

                    });
                } else {
                    this.Tablistingdata = [];
                }

            });
        },
        Selectedtabs(item) {
            if (item.is_required == 0) {
                item.isActive = !item.isActive;
                item.isSelected = item.isActive;
            }
        },
        validateInput(event) {
            const char = String.fromCharCode(event.which || event.keyCode);
            const input = event.target;
            const value = input.value || '';
            const selectionStart = input.selectionStart || 0;
            const selectionEnd = input.selectionEnd || 0;

            // Allow backspace, delete, tab, escape, enter, arrow keys, home, end
            if ([8, 9, 27, 13, 46, 37, 38, 39, 40, 35, 36].indexOf(event.keyCode) !== -1 ||
                // Allow Ctrl+A, Ctrl+C, Ctrl+V, Ctrl+X
                (event.keyCode === 65 && event.ctrlKey === true) ||
                (event.keyCode === 67 && event.ctrlKey === true) ||
                (event.keyCode === 86 && event.ctrlKey === true) ||
                (event.keyCode === 88 && event.ctrlKey === true)) {
                return;
            }

            // Allow only numbers and decimal point
            if (!/[0-9.]/.test(char)) {
                event.preventDefault();
                return;
            }

            // Get the text that will result from this keypress
            const textBefore = value.substring(0, selectionStart);
            const textAfter = value.substring(selectionEnd);
            const newValue = textBefore + char + textAfter;

            // Check if decimal point already exists
            if (char === '.' && value.indexOf('.') !== -1) {
                event.preventDefault();
                return;
            }

            // Validate format: max 5 digits before decimal, max 2 after
            const parts = newValue.split('.');
            const beforeDecimal = parts[0] || '';
            const afterDecimal = parts[1] || '';

            // Prevent 6th digit before decimal
            if (beforeDecimal.length > 5) {
                event.preventDefault();
                return;
            }

            // Prevent 3rd digit after decimal
            if (afterDecimal.length > 2) {
                event.preventDefault();
                return;
            }

            this.isValid = true;
        },
        formatInput(event, member) {
            const input = event.target;
            let value = input.value;

            if (value === '' || value === null || value === undefined) {
                member.ratePerHour = '';
                this.isValid = true;
                return;
            }

            // Convert to string
            value = String(value);

            // Remove any non-numeric characters except decimal point
            value = value.replace(/[^0-9.]/g, '');

            // Handle multiple decimal points - keep only the first one
            const decimalIndex = value.indexOf('.');
            if (decimalIndex !== -1) {
                const before = value.substring(0, decimalIndex);
                const after = value.substring(decimalIndex + 1).replace(/\./g, '');
                value = before + '.' + after;
            }

            // Split by decimal point
            const parts = value.split('.');
            let beforeDecimal = parts[0] || '';
            let afterDecimal = parts[1] || '';

            // Limit to 5 digits before decimal - remove 6th digit or more
            if (beforeDecimal.length > 5) {
                beforeDecimal = beforeDecimal.substring(0, 5);
            }

            // Limit to 2 digits after decimal - remove 3rd digit or more
            if (afterDecimal.length > 2) {
                afterDecimal = afterDecimal.substring(0, 2);
            }

            // Reconstruct the value
            let formattedValue = beforeDecimal;
            const hadDecimal = value.indexOf('.') !== -1;
            if (hadDecimal) {
                // If original value had decimal point, include it
                formattedValue = beforeDecimal + '.' + afterDecimal;
            }

            // Update the model value (v-model will update the input)
            if (formattedValue === '' || formattedValue === '.') {
                member.ratePerHour = '';
            } else {
                member.ratePerHour = formattedValue;
            }

            // Validate - ensure format is correct (max 5 before, max 2 after)
            this.isValid = beforeDecimal.length <= 5 && afterDecimal.length <= 2;
        },
        handlePaste(event, member) {
            event.preventDefault();
            const pastedText = (event.clipboardData || window.clipboardData).getData('text');

            if (!pastedText) return;

            // Process pasted text through formatInput logic
            let value = String(pastedText);

            // Remove any non-numeric characters except decimal point
            value = value.replace(/[^0-9.]/g, '');

            // Handle multiple decimal points - keep only the first one
            const decimalIndex = value.indexOf('.');
            if (decimalIndex !== -1) {
                const before = value.substring(0, decimalIndex);
                const after = value.substring(decimalIndex + 1).replace(/\./g, '');
                value = before + '.' + after;
            }

            // Split by decimal point
            const parts = value.split('.');
            let beforeDecimal = parts[0] || '';
            let afterDecimal = parts[1] || '';

            // Limit to 5 digits before decimal
            if (beforeDecimal.length > 5) {
                beforeDecimal = beforeDecimal.substring(0, 5);
            }

            // Limit to 2 digits after decimal
            if (afterDecimal.length > 2) {
                afterDecimal = afterDecimal.substring(0, 2);
            }

            // Reconstruct the value
            let formattedValue = beforeDecimal;
            if (value.indexOf('.') !== -1 && afterDecimal.length > 0) {
                formattedValue = beforeDecimal + '.' + afterDecimal;
            }

            // Update the model value
            member.ratePerHour = formattedValue === '' ? '' : formattedValue;
            this.isValid = beforeDecimal.length <= 5 && afterDecimal.length <= 2;
        },
        validate(value) {
            if (!value) return true;
            const [beforeDecimal, afterDecimal] = String(value).split('.');
            if (beforeDecimal && beforeDecimal.length > 5) {
                return false;
            }
            if (afterDecimal && afterDecimal.length > 2) {
                return false;
            }
            return true;
        },
        isChecked(val, csv) {
            if (!csv) return false;
            return csv.split(',').map(s => s.trim()).includes(val);
        },
        toggleValue(val, fieldInfo) {
            var ths = this;
            let current = fieldInfo.value ? fieldInfo.value.split(',').map(s => s.trim()).filter(Boolean) : [];
            if (current.includes(val)) {
                current = current.filter(v => v !== val);
            }
            else {
                current.push(val);
            }
            fieldInfo.value = current.join(',');
            const filterFields = ["location_id", "off_days", "planned_start_date", "planned_end_date"];
            const allFields = ths.FormSchemaa.flatMap(group => group.Data);
            const filtered = allFields.filter(f => filterFields.includes(f.name));
            var locationId = 0;
            var off_days = '';
            var startDate = '';
            var endDate = '';
            if (filtered.length > 0) {
                filtered.forEach(field => {
                    if (field.name == 'location_id') {
                        locationId = field.value == '' ? 0 : field.value;
                    }
                    if (field.name == 'off_days') {
                        off_days = field.value;
                    }
                    if (field.name == 'planned_start_date') {
                        startDate = field.value;
                    }
                    if (field.name == 'planned_end_date') {
                        endDate = field.value;
                    }
                })
                ths.GetProjectWorkingDays(locationId, off_days, startDate, endDate);
            }
        },
        ProjectBaseRate: function () {
            var vm = this;
            vm.isLoading = true;
            DataService.ProjectBaseRate().then((response) => {
                if (response.data.result.DATA.length > 0) {
                    vm.BaseRate = response.data.result.DATA[0].CONFIG_DATA_VALUE;
                    vm.isLoading = false;
                }
