        },
        GetIndustryType: function () {
            this.isLoading = true;
            DataService.GetTemplateList().then((response) => {            
                if (response.data.result.DATA.length > 0) {                    
                    this.IndustryTypeTemplate = response.data.result.DATA;
                    this.IndustryTypeTemplate.forEach((x) => {
                        x.clicked = false
                    }); 
                    this.isLoading = false;                   
                }
