        },
        GetTemplateListData:async function (itm) {
            var vm = this;
            debugger
            vm.ShowSelectedIndustry = itm.name;
            vm.isLoading = true;
            var url = `IndustryTypeId=${itm.id}`;
            itm.clicked = true;
            vm.pindustrytypeid = itm.id;
            const index = vm.IndustryTypeTemplate.filter(i => i.id === itm.id);
            vm.IndustryTypeTemplate.forEach((x) => {
                if (x.id === itm.id) {
                    x.clicked = true;
                }
                else {
                    x.clicked = false;
                }
            });
            if (index != null) {
                vm.$set(vm.IndustryTypeTemplate, index, { ...itm });
            }
            vm.isShowTemplate = true;
            await DataService.GetTemplateListData(url).then((response) => {
                vm.isLoading = false;
                var result = response.data.result;
                if (result != '' && result != null) {
                    if (result.DATA != null && result.DATA != '' && result.DATA != []) {
                        vm.GetTemplateList = response.data.result.DATA;
                        vm.GetTemplateList.forEach((x) => {
                            if (x.ImagePath && typeof x.ImagePath === 'string') {
                                x.ImagePath = x.ImagePath.split(',');
                            } else {
                                x.ImagePath = [];
                            }
                            x.clicked = false
                        });
                    }
                }

            })
        },
        IsBack: function () {

            this.ShowSelectedtemplat = '';
            this.isShowTemplate = false;
        },
        setProjectTemplate: function (itm) {
            var vm = this;
            vm.selectedTemplateId = itm.id;
            vm.ShowSelectedtemplat = itm.name;
            itm.clicked = true;
            vm.ptemplateid = itm.id;
            const index = vm.GetTemplateList.findIndex(i => i.id === itm.id);
            vm.GetTemplateList.forEach((x) => {
                if (x.id === itm.id) {
                    x.clicked = true;
                }
                else {
                    x.clicked = false;
                }
            });
            if (index !== -1) {
                vm.$set(vm.GetTemplateList, index, { ...itm });
