            if (vm.ptemplateid == null || vm.ptemplateid == "") {
                this.ShowAlert(this.$t("Please select a Template"), "failure", this.$t('Alert'));
                return false;
            }
            if (vm.ptemplateid != null && vm.pindustrytypeid != null && data == 1) {
                vm.step2 = '#step2';
                vm.TabSelected = 2;
            }
            if (data == 2) {
                
                this.$refs.AddProjectForm.validateForm.validate().then(result => {
                    result=true;
                    if (result) {
                        vm.step3 = '#step3';
