        AdvancedField: function () {
            var vm = this;
            const visibleFieldNames = [
                'base_rate', 'estimated_hours', 'off_days', 'status_id',
                'channel_id', 'priority_id', 'tag_id', 'is_billable',
                'is_hourly', 'currency_id', 'location_id',
