        GetSelectedCurrency: function (typevalue) {
            var vm = this;
            vm.FormSchemaa.forEach((group, gi) => {
                $.each(group.Data, $.proxy(function (index, item) {
                    if (item.name === "base_rate" || item.name === "estimated_cost") {
                        if (typevalue.value === "" || typeof typevalue.value === "undefined" || typevalue.value === null) {
                            return;
                        } else {
                            var getlabel = typevalue.config.OptionsForBind.filter(x => x.value == typevalue.value);
                            vm.Currency=getlabel[0].first_value;
                            item.label = `Project Rate (${getlabel[0].first_value})`;
                            if (item.name === "estimated_cost") {
                                item.label = `Project Amount (${getlabel[0].first_value})`;
                            }
                        }
                    }
                }));
            });
        },
        GetProjectAmount: function (typevalue, type) {
            var vm = this;
            var baseRate = 0;
            var projectHours = 0;
            var ProjectAmount = 0;
            vm.FormSchemaa.forEach((group, gi) => {
                if (type == 'ProjectHours') {
                    $.each(group.Data, $.proxy(function (index, item) {
                        if (item.name == "base_rate") {
                            baseRate = item.value;

                            if (typevalue.value == "" || typeof typevalue.value == "undefined" || typevalue.value == null) {
                                ProjectAmount = 0 * baseRate;
                            }
                            else {
                                ProjectAmount = (parseFloat(typevalue.value) * baseRate).toFixed(2);
                            }
                        }
                    }));
                } else {
                    $.each(group.Data, $.proxy(function (index, item) {
                        if (item.name == "estimated_hours") {
                            projectHours = item.value;
                            if (typevalue.value == "" || typeof typevalue.value == "undefined" || typevalue.value == null) {
                                ProjectAmount = 0 * projectHours;
                            }
                            else {
                                ProjectAmount = (parseFloat(typevalue.value) * projectHours).toFixed(2);
                            }
                        }
                    }));
                }
                $.each(group.Data, $.proxy(function (index, item) {
                    if (item.name == "estimated_cost") {
                        item.value = ProjectAmount;
                        item.validationRules.required = false;
                    }
                }));
            })
        },
        GetProjectHours: function (itemvalue) {
            var vm = this;
            var ProjectHours = 0;
            if (itemvalue.value == "" || typeof itemvalue.value == "undefined" || itemvalue.value == null) {
                itemvalue = 0;
            }
            vm.FormSchemaa.forEach((group, gi) => {
                $.each(group.Data, $.proxy(function (index, item) {
                    if (item.name == "base_rate") {
                        if (item.value == "" || typeof item.value == "undefined" || item.value == null) {
                            ProjectHours = 0;
                        }
                        else if (parseInt(itemvalue.value) > 0) {
                            ProjectHours = parseFloat(itemvalue.value) / parseFloat(item.value);
                        }
                    }
                }));
                $.each(group.Data, $.proxy(function (index, item) {
                    if (item.name == "estimated_hours") {
                        item.value = Math.round(ProjectHours);
                        item.validationRules.required = false;
                    }
                }));
            })
        },
