            if (selectAll) {
                const total = allCheckboxes.length;
                const checkedCount = Array.from(allCheckboxes).filter(cb => cb.checked).length;
                selectAll.checked = (total > 0 && total === checkedCount);
            }
        },
        SaveProject() {            
            var ths = this;
            ths.isLoading = true;
            var team = [];
            var CustomFieldArray = ths.$refs.AddProjectForm.ConvertDynamicFormObjToCustomFieldObj(ths.FormSchemaa);
            if (parseInt(ths.ProjectId) == 0) {
                if (ths.teamType == 'team') {
                    ths.SaveTeams.forEach((item) => {
                        var teamObj = {
                            team_id: item.USER_ID == undefined ? item.TEAM_ID : item.USER_ID,
                            status_id: 1001
                        }
                        team.push(teamObj)
                    })
                    let obj = {
                        custom_field_id: 0,
                        field_name: 'project_team_type',
                        field_value: ths.teamType
                    }
                    CustomFieldArray.push(obj);
                }
                else {
                    const resultString = ths.projectTeams.map(item => item.USER_ID).join(',');
                    const userIds = resultString.split(',');
                    let obj = {
                        custom_field_id: 0,
                        field_name: 'project_team_type',
                        field_value: ths.teamType
                    }
                    var teamData = ths.TeamMemberData.filter(member => userIds.includes(member.USER_ID.toString()));
                    teamData.forEach((itm) => {
                        var teamObj = {
                            user_id: itm.USER_ID,
                            sold_horly_rate: itm.ratePerHour,
                            designation_id: null,
                            user_type_id: itm.CheckIsName == true ? 2 : itm.USER_TYPE_ID,
                            alias_name: itm.ALIASNAME,
                            is_show_alias: itm.CheckAliasName == true ? true : false,
                            status_id: 1001,
                        }
                        team.push(teamObj)
                    });
                    let filteredData = ths.TeamMemberData.filter(member => member.USER_ID === ths.userId);
                    if (filteredData.length > 0) {
                        var userExists = team.some(item => item.user_id === filteredData[0].USER_ID);
                        if (!userExists) {
                            team.push({
                                user_id: filteredData[0].USER_ID,
                                sold_horly_rate: filteredData[0].ratePerHour,
                                designation_id: null,
                                user_type_id: filteredData[0].USER_TYPE_ID,
                                alias_name: filteredData[0].ALIASNAME,
                                is_show_alias: filteredData[0].ShowAliasName,
                                status_id: 1001
                            });
                        }
                    }
                }
            }
            CustomFieldArray.forEach((x) => {
                if (x.field_name == 'tag_id') {
                    if (!ths.isBlank(x.field_value)) {
                        var val = "";
                        x.field_value.forEach((itm) => {
                            val += itm.value;
                            val += ',';
                        });
                        x.field_value = val;
                    }
                }
                if (x.field_name == 'is_ongoing' || x.field_name == 'is_hourly' || x.field_name == 'is_billable') {
                    if (x.field_value == null || x.field_value == '') {
                        x.field_value = 0;
                    } else {
                        x.field_value = x.field_value;
                    }
                }
                if (x.field_name == 'project_start_date') {
                    x.field_value = ths.ProjectStartDate;
                }
                if (x.field_name == 'modified_by') {
                    x.field_value = ths.userId;
                }
                if (x.field_name == 'created_by') {
                    x.field_value = ths.userId;
                }
                if (x.field_name == 'project_description') {
                    x.field_value = ths.Descriptionn;
                }
                if (x.field_name == 'project_team') {
                    x.field_value = team;
                }
                if (x.field_name == 'project_tab') {
                    x.field_value = ths.Tablistingdata.filter(x => x.isSelected == true);
                }
                if (ths.ProjectId > 0) {
                    if (x.field_name == 'industry_type_id') {

                        x.field_value = ths.ptemplateid;
                    }
                    if (x.field_name == 'template_id') {

                        x.field_value = ths.pindustrytypeid;
                    }
                }
                else {
                    if (x.field_name == 'industry_type_id') {
                        x.field_value = ths.pindustrytypeid;
                    }
                    if (x.field_name == 'template_id') {
                        x.field_value = ths.ptemplateid;
                    }
                }
            });            
            var obj = {
                data: CustomFieldArray,
                moduleCode: "PROJECT",
                subModuleCode: "PROJECT_DETAIL"
            }

            DataService.SaveDynamicForm(JSON.stringify(obj)).then(function (response) {
                if (response != null && response.data != null && response.data[0].Status == "Success") {
                    if (ths.ProjectId > 0) {
                        ths.ShowAlert(ths.$t('UpdatedSuccess', [ths.$t('Project')]), "success", true, ths.$t("Alert"));
                        if (ths.Type == 'Edit') {
                            ths.$parent.FetchData();
                            ths.$router.push({ name: 'ProjectList' });
                        } else {
                            ths.$parent.UpdateOverView();
                        }
                        ths.CloseTemplate();
                    }
                    else {
                        if (response.data[0].Value.MSG == 'DUPLICATE') {
                            ths.ShowAlert(ths.$t('AlreadyExists', [ths.$t('Project')]), "warning", true, ths.$t("Alert"));
                        } else {
                            ths.ShowAlert(ths.$t('AddedSuccess', [ths.$t('Project')]), "success", true, ths.$t("Alert"));
                            ths.$parent.FetchData();
                            ths.CloseTemplate();
                            ths.ProjectId = response.data[0].Value.MAIN_ID;
                            let projectNameField = CustomFieldArray.find(x => x.field_name === "project_name");
                            let projectName = projectNameField ? projectNameField.field_value : "";
                            let projectTeamField = CustomFieldArray.find(x => x.field_name === "project_team");
                            let projectTeam = projectTeamField ? projectTeamField.field_value : [];
                            let payload = {
                                projectId: ths.ProjectId,
                                projectName: projectName,
                                projectContent: ths.$t('newprojectcreated'),
                                projectTeam: projectTeam
                            };
                            DataService.SendAddProjectNotification(JSON.stringify(payload)).then((res) => {
                                console.log("Notification Response:", res.data);
                            });
                            setTimeout(function () {
                                $("#modalAddProject").modal("hide");
                            }, 1000);
                            ths.$router.push({ name: 'ProjectDetail', params: { projectId: response.data[0].Value.MAIN_ID } });
                        }

                    }
                }
            })
            ths.isLoading = false;
        },

        SelectAllChekcboxes(evt) {

            const vm = this;
            const isChecked = evt.target.checked;
            const checkboxes = document.getElementsByClassName("custom-control-input addmem checkboxid");
            if (isChecked) {
                vm.projectTeams = [];
                for (let i = 0; i < checkboxes.length; i++) {
                    checkboxes[i].checked = true;

                    if (vm.teamType === 'team') {
                        vm.SaveTeams.push({ USER_ID: checkboxes[i].value });
                    } else {
                        vm.TeamMemberData = vm.TeamMemberData.map(itm =>
                            itm.USER_ID === parseInt(checkboxes[i].value)
                                ? { ...itm, ShowAliasName: false, ShowIsPM: false }
                                : itm
                        );
                        vm.projectTeams.push(vm.TeamMemberData[i]);
                    }
                }
            } else {
                for (let i = 0; i < checkboxes.length; i++) {
                    checkboxes[i].checked = false;
                }

                if (vm.teamType === 'team') {
                    vm.SaveTeams = [];
                } else {
                    vm.projectTeams = [];
                    vm.TeamMemberData = vm.TeamMemberData.map(itm => ({
                        ...itm,
                        ShowAliasName: true,
                        ShowIsPM: true
                    }));
                }
            }
        },


        GetTeamOrUser: async function (type) {

            var ths = this
            var selectAll = document.getElementById("chkAll_28");
            if (selectAll) {
                selectAll.checked = false;
            }
            ths.teamType = type;
            if (ths.teamType == "user") {
                await ths.FetchMemberListing();
            } else if (ths.teamType == "team") {
                await ths.FetchTeamListing();
            }
        },
        FetchMemberListing: async function () {

            var ths = this;
            ths.isLoading = true;
            var url = `search=PROJECT&projectId=${ths.ProjectId}`
            await DataService.AddMemberInProject(url).then((response) => {
                if (response.data.length > 0) {
                    ths.TeamMemberData = response.data;
                    ths.TeamMemberData.forEach(item => {
                        item.ShowAliasName = true;
                        item.ShowIsPM = true;
                        item.CheckAliasName = false;
                        item.CheckIsName = false;
                        ths.isLoading = false;
                        item.isInSearch = true;
                    });
                    ths.updatecomponent += 1;
                }
            });
        },
        FetchTeamListing: async function () {

            var ths = this;
            ths.isLoading = true;
            var url = `refCode=PROJECT&refId=${ths.ProjectId}`
            await DataService.GetTeamForAssociate(url).then((response) => {

                ths.isLoading = false;
                if (response.data != null && response.data.result.length > 0) {
                    let teams = response.data.result;
                    teams.forEach((x) => { x.isInSearch = true });
                    ths.teamData = teams;
                    ths.updatecomponent += 1;
                }
            });
        },
        closeshowLightbox() {
            var vm = this;
            vm.images = [];
            vm.showLightbox = false;
        },
        openLightbox(attachmentPath) {
            var vm = this;
            var fileName;
            if (Array.isArray(attachmentPath)) {
                fileName = attachmentPath;
            }
            fileName.forEach((itm) => {
                var obj = {
                    path: itm,
                    caption: itm.split('/').pop().split('.')[0]
                }
                vm.images.push(obj);
            })
            vm.showLightbox = true;
        },
        BindImageURL(url) {
            if (url == null || url == undefined) {
                return '';
            } else if (Array.isArray(url)) {
                return url[0] || '';
            } else {
                return url.split(',')[0];
            }
        },
        AddTeamProject() {
            this.isShowProjectPopupTeam = true;          
            window.open(routeData.href, "_blank");
        }
    }
}
</script>

