<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Clone') }} {{ $t('Project') }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm"
                            v-on:OnSubmit="OnSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import DataService from '../../services/DataService'
export default{
    props:{
        ProjectId:{
            type: Number,
            required: true,
        }
    },
    data(){        
        return{
            isLoading:false,
            selectedProjectId:0,        
            FormSchema: [               
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextField",                 
                            label: this.$t('Project Name'),
                            name: "ProjectName",
                            value: "",                           
                            placeholder: this.$t('Enter Project Name'),
                            validationRules: { "required": true, max: 100 },
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
        }        
    },
    created:function(){
        var vm=this;        
        vm.companyId = vm.GetUserInfo.CompanyId;
        if(this.ProjectId != null){
            this.selectedProjectId=this.ProjectId;
        }
    },
    methods:{        
        Close:function(){
            this.$parent.IsCloneProject=false;
        },
        OnSubmit:function(){ 
            debugger  
            var vm=this;
            if(vm.ProjectId != 0){
                var url=`id=0&name=${vm.FormSchema[0].Data[0].value}&type=PROJECT&selectedProjectId=${vm.selectedProjectId}&cloneProjectName=${vm.FormSchema[0].Data[0].value}`             
                DataService.SaveCloneProject(url).then(function (response) {                    
                    if (response.data.result== "1") {   
                        vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('Project')]), "warning", true, vm.$t("Alert"));                        
                    }
                    else {                      
                        vm.ShowAlert(vm.$t('CloneSuccess', [vm.$t('Project')],[vm.$t(vm.FormSchema[0].Data[0].value)]), "success", true, vm.$t("Alert"));
                        vm.Close();
                        vm.$parent.FetchData();
                    } 
                });                
            }
        }
    }
}
</script>